diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..6bd2f727b58d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1229,23 +1229,48 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Division must be by power-of-2, but not the minimum signed value.
   Value *X;
   const APInt *DivC;
-  if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
-      DivC->isNegative())
+  Value *SDivOp = nullptr;
+  Value *SExtOp = nullptr;
+  // Check operand 0 is SDiv, operand 1 is SExt icmp
+  if (match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) &&
+      !DivC->isNegative()) {
+    SDivOp = Add.getOperand(0);
+    SExtOp = Add.getOperand(1);
+  } else if (match(Add.getOperand(1), m_SDiv(m_Value(X), m_Power2(DivC))) &&
+             !DivC->isNegative()) {
+    SDivOp = Add.getOperand(1);
+    SExtOp = Add.getOperand(0);
+  } else {
     return nullptr;
+  }

   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // Also accept equality compare with mask: sext (icmp eq (X & Mask), Mask)
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
-  if (!match(Add.getOperand(1),
+  const APInt *CmpConstant;
+  // Match sext(icmp(Pred, X & MaskC, CmpConstant))
+  if (!match(SExtOp,
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CmpConstant)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  if (*MaskC != ExpectedMask)
+    return nullptr;
+
+  // Check predicate and constant:
+  // Case 1: ugt with SMin
+  bool Valid = false;
+  if (Pred == ICmpInst::ICMP_UGT && *CmpConstant == SMin)
+    Valid = true;
+  // Case 2: eq with Mask - only valid for divisor 2 because all low bits must be set
+  else if (Pred == ICmpInst::ICMP_EQ && *CmpConstant == ExpectedMask && *DivC == 2)
+    Valid = true;
+  if (!Valid)
     return nullptr;

   // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)

